import{_ as i,o as a,c as e,a as l}from"./chunks/framework.8tiMeCK-.js";const c=JSON.parse('{"title":"6.5  使用 slabinfo 及其配套工具","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch06_5.md","filePath":"notes/linux_kernel_debugging/ch06_5.md","lastUpdated":null}'),n={name:"notes/linux_kernel_debugging/ch06_5.md"};function t(p,s,o,h,r,d){return a(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="_6-5-使用-slabinfo-及其配套工具" tabindex="-1">6.5 使用 slabinfo 及其配套工具 <a class="header-anchor" href="#_6-5-使用-slabinfo-及其配套工具" aria-label="Permalink to &quot;6.5  使用 slabinfo 及其配套工具&quot;">​</a></h1><h4 id="工具箱里的新家伙" tabindex="-1">工具箱里的新家伙 <a class="header-anchor" href="#工具箱里的新家伙" aria-label="Permalink to &quot;工具箱里的新家伙&quot;">​</a></h4><p>到现在为止，我们一直是在内核「内部」打转——看内核日志，解读 panic 信息，或者对着 hex dump 发呆。这当然很重要，但有时候，你需要像个抽离的观察者那样，站在外面往里看。</p><p>这就需要一把趁手的「外窥镜」。</p><p>你可能会问，<code>/proc/slabinfo</code> 那个文件我们不是提过好几次了吗？是的，但直接读那个文件就像在读一长串没有逗号的句子——信息全在那里，但人类读起来太累了。你需要一个能把这些数据结构化、甚至帮你分析出来的工具。</p><p>这个工具就是 <code>slabinfo</code>。</p><p>有点反直觉的是，这个虽然是用户空间程序，但它其实就住在内核源码树里： <code>tools/vm/slabinfo.c</code></p><p>编译它非常简单，不需要折腾复杂的 Kbuild 系统。只要进入源码树的 <code>tools/vm</code> 目录，直接敲 <code>make</code> 就行了。编译出来是个二进制文件，为了方便调用，你可以把它软链接到 <code>/usr/bin/slabinfo</code>。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slabinfo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lrwxrwxrwx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 71</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Nov</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 16:26</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/bin/slabinfo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/linux-5.10.60/tools/vm/slabinfo</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>在开始之前，先跑一下 <code>-h</code>（或者 <code>--help</code>）。你会看到一大坨参数。别被吓到了，很多参数其实是针对特定场景的。下图展示的是 5.10.60 内核版本的所有参数（Figure 6.6）：</p><p><em>(Figure 6.6 – The help screen of the kernel slabinfo utility)</em></p><p>有几点需要你心里有数：</p><ul><li><strong>默认行为</strong>：<code>slabinfo</code> 默认只显示<strong>有数据</strong>的 slab 缓存（这等同于带上了 <code>-l</code> 参数）。如果你想看那些空的缓存，运行 <code>slabinfo -e</code>。</li><li><strong>前提条件</strong>：不是所有参数都能随手用。大部分功能需要内核开启了 <code>CONFIG_SLUB_DEBUG=y</code>。好消息是，大多数发行版内核默认都开了这个。还有些功能需要你在内核启动参数里通过 <code>slub_debug</code> 传进去特定的标志。</li><li><strong>权限</strong>：你必须是 root。</li></ul><h4 id="先来一把「体检」" tabindex="-1">先来一把「体检」 <a class="header-anchor" href="#先来一把「体检」" aria-label="Permalink to &quot;先来一把「体检」&quot;">​</a></h4><p>让我们先不接任何参数跑一次，看看它能吐出什么。</p><p>这里我们只看表头和一个具体的例子（<code>kmalloc-32</code> 缓存）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slabinfo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Objects</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Objsize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Space</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Slabs/Part/Cpu</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O/S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> %Fr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> %Ef</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Flg</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slabinfo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;^kmalloc-32&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kmalloc-32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 35072</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 32</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">   1.1M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">   224/0/50</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">     128</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这行输出有点挤，我们把它拆开揉碎了看。每一列都是这块缓存的「体检指标」：</p><ul><li><strong>Name</strong>: 缓存的名字（这里是 <code>kmalloc-32</code>）。</li><li><strong>Objects</strong>: 当前分配了多少个对象（35072 个）。</li><li><strong>Objsize</strong>: 单个对象的大小（32 字节，这很符合预期）。</li><li><strong>Space</strong>: 这些对象占用的总内核内存空间（大约 1.1MB，基本就是 <code>Objects * Objsize</code>）。</li><li><strong>Slabs/Part/Cpu</strong>: 这是一个三元组，分别代表<strong>满的 slab 数量</strong>、<strong>部分空的 slab 数量</strong> 和 <strong>每 CPU slab 数量</strong>。这个比例能告诉你系统的碎片化程度。</li><li><strong>O/S (Objects per Slab)</strong>: 每个 slab 能装多少个对象（128 个）。</li><li><strong>O (Order)</strong>: 向页分配器申请内存的阶数。0 代表 1 页（$2^0$），1 代表 2 页（$2^1$），以此类推。这里如果是 0，说明是用单页来承载这些对象的。</li><li><strong>%Fr</strong>: 空闲内存的百分比。</li><li><strong>%Ef</strong>: 有效内存使用率百分比。</li><li><strong>Flg</strong>: 标志位。这里显示了该缓存启用的特殊属性（下面会细说）。</li></ul><p>如果你想看这行打印到底是怎么生成的，可以直接去看源码： <a href="https://elixir.bootlin.com/linux/v5.10.60/source/tools/vm/slabinfo.c#L640" target="_blank" rel="noreferrer">https://elixir.bootlin.com/linux/v5.10.60/source/tools/vm/slabinfo.c#L640</a></p><p>关于最右侧的 <strong>Flg</strong> 标志位，它们代表了 slab 缓存的各种属性，含义如下：</p><ul><li><strong>*</strong>: 存在别名</li><li><strong>d</strong>: DMA 内存</li><li><strong>A</strong>: 硬件缓存行对齐</li><li><strong>P</strong>: Poisoned（已投毒，用于检测未初始化访问）</li><li><strong>a</strong>: 激活了回收统计</li><li><strong>Z</strong>: Red Zoned（红区，用于检测越界）</li><li><strong>F</strong>: Sanity checks on（开启健全性检查）</li><li><strong>U</strong>: User tracking（记录谁分配了它）</li><li><strong>T</strong>: Traced（正在被跟踪）</li></ul><p>另外，如果你加了 <code>-D</code>（Display active）选项，输出的列格式会发生变化，展示更详细（但也更宽）的信息。</p><h4 id="谁是内存大户" tabindex="-1">谁是内存大户？ <a class="header-anchor" href="#谁是内存大户" aria-label="Permalink to &quot;谁是内存大户？&quot;">​</a></h4><p>这时候一个常见的工程问题冒出来了：在这么多 slab 缓存里，到底谁占用了最多的内核内存？</p><p><code>slabinfo</code> 提供了两种思路来回答这个问题：</p><ol><li>用 <code>-B</code> 参数，它会显示占用的字节数，方便你手工排序。</li><li>更简单的方法，直接用 <code>-S</code> 参数。它会让 <code>slabinfo</code> 按照占用空间从大到小排序，并且自动带上人类可读的单位（KB, MB 等）。</li></ol><p>下图展示了用 <code>-S</code> 查看占用内存前 10 名的 slab 缓存（Figure 6.7）：</p><p><em>(Figure 6.7 – The top 10 slab caches sorted by total kernel memory space taken)</em></p><p>你可以看到，通常排名靠前的都是通用的 <code>kmalloc-*</code> 或者是某些高频内核数据结构。</p><p>这里有个很有意思的插曲：<code>-U</code>（Show unreclaimable slabs only，只显示不可回收的 slab）这个选项的诞生，完全是因为一次真实的系统恐慌。 故事是这样的：系统的不可回收 slab 内存占用一度逼近 100%，导致 OOM Killer（内存溢出杀手）甚至找不到候选进程来杀，最后直接 panic。为了以后排查这种绝境，开发者提交了一个补丁，不仅让 <code>slabinfo</code> 能显示这些顽固分子，也让 OOM Killer 的代码路径能打印它们。这个补丁在 4.15 内核合入。你可以感受一下这个 commit 的沉重感： <a href="https://github.com/torvalds/linux/commit/7ad3f188aac15772c97523dc4ca3e8e5b6294b9c" target="_blank" rel="noreferrer">https://github.com/torvalds/linux/commit/7ad3f188aac15772c97523dc4ca3e8e5b6294b9c</a></p><h4 id="浪费去哪了-内部碎片" tabindex="-1">浪费去哪了？（内部碎片） <a class="header-anchor" href="#浪费去哪了-内部碎片" aria-label="Permalink to &quot;浪费去哪了？（内部碎片）&quot;">​</a></h4><p>接下来是 <code>-L</code>（sort by loss，按损失排序）选项。这个「损失」（Loss），其实换个词你会更熟悉——<strong>内部碎片</strong>。</p><p>slab 层采用的是「最佳拟合」模型。当你请求 100 字节时，内核没法给你切 100 字节出来，它会把你塞进 <code>kmalloc-128</code> 的缓存里（因为 96 装不下）。 结果是：你请求了 100 字节，实际占用了 128 字节。 那 28 字节的差价，就是所谓的 Loss 或 Waste。</p><p>运行 <code>sudo slabinfo -L |head</code>，你会看到按照浪费量降序排列的缓存列表（看第四列 <code>Loss</code>）。这对于评估系统的内存效率非常有帮助——有时候你会发现，某些结构体稍微优化一下大小，就能省下惊人的碎片空间。</p><h4 id="深挖单个缓存" tabindex="-1">深挖单个缓存 <a class="header-anchor" href="#深挖单个缓存" aria-label="Permalink to &quot;深挖单个缓存&quot;">​</a></h4><p>如果你发现某个缓存看起来很可疑，或者只是单纯想深入研究它，<code>-r</code>（report，报告）选项是你的好帮手。</p><p>默认情况下，它会吐出所有缓存的详细统计。更实用的做法是配合正则表达式。比如，只想看虚拟内存相关的缓存：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slabinfo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vm.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这会显示所有匹配 <code>vm.*</code> 模式的缓存详情。如果之前启用了 SLUB 调试标志（比如 U），这里甚至能看到是谁、在哪里 alloc/free 了这些对象。</p><p>有时候你会看到一个名字很生疏的缓存，不知道它是干嘛的。这时 <code>-a</code>（或 <code>--aliases</code>）选项就派上用场了，它会显示这个缓存是哪个内核对象的别名，帮你揭开面纱。</p><p>想看全局概览？<code>-T</code> 选项会显示所有缓存的汇总快照：有多少个缓存、活跃多少、总共用了多少内存等。如果你觉得还不够过瘾，<code>-X</code> 选项会提供扩展版的详细信息（Figure 6.8）。</p><p><em>(Figure 6.8 – Screenshot showing extended summary information via slabinfo -X)</em></p><p>最后，如果想看<strong>所有</strong>缓存（包括空的），用 <code>-z</code>（zero）参数。</p><h4 id="也就是这个参数-能救你的命" tabindex="-1">也就是这个参数，能救你的命 <a class="header-anchor" href="#也就是这个参数-能救你的命" aria-label="Permalink to &quot;也就是这个参数，能救你的命&quot;">​</a></h4><p>这里有两个专门用于调试的选项：<code>-d</code> 和 <code>-v</code>。 它们都有一个硬性前提：你的系统必须带 <code>slub_debug</code> 内核参数启动，而且这个参数得是非空值。</p><p>让我们先看点直观的。当你用 <code>slub_debug=FZPU</code> 启动后，你会发现所有 slab 缓存的标志位里，哪怕之前什么都没有，现在也至少挂着 <code>PZFU</code> 这几个字母（Figure 6.9）。</p><p><em>(Figure 6.9 – Partial screenshot – the focus is on the SLUB debug flags being set)</em></p><p>这表示内核已经强制给所有缓存加上了这些调试属性。</p><p>关于 <code>-d</code> 选项：</p><ul><li>单独运行 <code>slabinfo -d</code> <strong>会把调试关掉</strong>。这很不直观，对吧？但这和内核参数 <code>slub_debug</code> 的行为是一致的。</li><li>如果你想<strong>打开</strong>某些调试标志，需要显式传参，比如 <code>--debug=fzput</code>。</li></ul><p>这背后的黑盒机制其实很简单：当你执行 <code>--debug=fzput</code> 时，<code>slabinfo</code> 工具（作为 root）会去写 <code>/sys/kernel/slab/&lt;slabname&gt;/</code> 下面的对应伪文件，把它们置为 1。</p><p>具体映射关系如下：</p><ul><li><code>f|F</code> -&gt; 写入 <code>/sys/kernel/slab/&lt;slabname&gt;/sanity_checks</code></li><li><code>z|Z</code> -&gt; 写入 <code>/sys/kernel/slab/&lt;slabname&gt;/red_zone</code></li><li>以此类推...</li></ul><p>干脏活的代码在这里： <a href="https://elixir.bootlin.com/linux/v5.10.60/source/tools/vm/slabinfo.c#L717" target="_blank" rel="noreferrer">https://elixir.bootlin.com/linux/v5.10.60/source/tools/vm/slabinfo.c#L717</a></p><p>然后是 <code>-v</code>（validate，验证）选项。这个选项会强制 SLUB 遍历指定缓存里的所有对象，检查元数据的有效性。一旦发现不对劲，它会把诊断信息直接喷到内核日志里。</p><p>这和你之前看到的那种「内核自己报错」的格式是一模一样的。实际上，<code>slabinfo -v</code> 的本质就是往 <code>/sys/kernel/slab/&lt;slabcache&gt;/validate</code> 里写个 1。</p><p>这对于排查现网的怀疑有内存破坏的系统非常有用——主动触发一次全盘扫描，看看有没有藏在深处的炸弹。</p><p>顺便提一句，内核源码里甚至还有一个 <code>slabinfo-gnuplot.sh</code> 脚本，能把 slab 的运行情况画成图。想玩可视化的话，可以去读一下内核文档里的说明： Documentation/vm/slub.txt (Extended slabinfo mode and plotting section)</p><h4 id="那个老伙计-proc-slabinfo" tabindex="-1">那个老伙计：/proc/slabinfo <a class="header-anchor" href="#那个老伙计-proc-slabinfo" aria-label="Permalink to &quot;那个老伙计：/proc/slabinfo&quot;">​</a></h4><p>当然，内核本身就通过 procfs 暴露了这些信息，即 <code>/proc/slabinfo</code>。这实际上也是 <code>slabtop</code> 等工具的数据源。同样需要 root 权限读。</p><p>它的格式非常详细（甚至有点啰嗦）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/slabinfo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slabinfo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2.1</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># name &lt;active_objs&gt; &lt;num_objs&gt; &lt;objsize&gt; &lt;objperslab&gt; &lt;pagesperslab&gt; : </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tunables</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">limi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">batchcoun</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sharedfacto</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">r</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slabdata</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">active_slab</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">num_slab</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sharedavai</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>下图是实际数据的一瞥（Figure 6.10）：</p><p><em>(Figure 6.10 – A screenshot showing some data from /proc/slabinfo)</em></p><p>关于怎么解读这些列，<code>man slabinfo(5)</code> 写得很清楚。不过要注意，手册页稍微有点老了，有些统计信息主要是为了老式的 SLAB 分配器设计的。</p><p>还有个老朋友 <code>vmstat</code>。加上 <code>-m</code> 参数，它也能显示 slab 统计。它本质上也是读 <code>/proc/slabinfo</code>。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vmstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="像看-top-一样看-slab-slabtop" tabindex="-1">像看 top 一样看 slab：slabtop <a class="header-anchor" href="#像看-top-一样看-slab-slabtop" aria-label="Permalink to &quot;像看 top 一样看 slab：slabtop&quot;">​</a></h4><p>既然有 <code>top</code> 看 CPU，那有没有看 slab 的 <code>top</code>？ 当然有，它就叫 <code>slabtop</code>。</p><p>它的用法和 <code>top</code> 几乎一模一样，实时刷新，默认按对象数量排序（你可以用 <code>-s</code> 改变排序字段）。它也是基于 <code>/proc/slabinfo</code> 的数据，所以需要 root。</p><p>跑起来之后，你会发现除了那些特定的内核结构体缓存，小尺寸的通用缓存（<code>kmalloc-*</code> 系列）通常是系统的劳模，被调用得最频繁。</p><h4 id="更前沿的视角-slabratetop" tabindex="-1">更前沿的视角：slabratetop <a class="header-anchor" href="#更前沿的视角-slabratetop" aria-label="Permalink to &quot;更前沿的视角：slabratetop&quot;">​</a></h4><p>最后，是一个比较新的成员——基于 eBPF 的 <code>slabratetop</code>（你的系统上可能叫 <code>slabratetop-bpfcc</code>）。</p><p>前面提到的工具大多是「存量统计」，而 <code>slabratetop</code> 展示的是「增量速率」。它实时显示内核 slab 缓存的分配速率（每秒多少次）和总字节数，刷新频率默认是一秒。</p><p>它内部是通过跟踪 <code>kmem_cache_alloc</code> 这个关键的内核 API 来实现统计的。</p><p>比如，想以 5 秒为间隔，看 3 次采样：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slabratetop-bpfcc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这对分析系统的动态行为非常有帮助，能让你看到哪块内存正处于「高并发分配」的状态。</p><h4 id="实战演练-谁在吃我的内存" tabindex="-1">实战演练：谁在吃我的内存？ <a class="header-anchor" href="#实战演练-谁在吃我的内存" aria-label="Permalink to &quot;实战演练：谁在吃我的内存？&quot;">​</a></h4><p>好了，工具箱打开了，怎么用它们来解决实际问题？</p><p>最常见的一个问题就是：<strong>内存去哪了？</strong></p><p>这分两层：用户空间和内核空间。 如果是用户空间进程，用 <code>smem</code>、<code>ps</code> 或者直接读 <code>/proc/*/status</code> 就能搞定。比如想找物理内存（RSS）占用前 10 的进程：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;^VmRSS&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/status</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sed</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;s/kB$//&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sort</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k3n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>但如果你怀疑是内核在偷吃内存，特别是 <strong>slab 内存</strong>，这就有点意思了。我们来推演一个排查场景：</p><ol><li><strong>第一步</strong>：用 <code>slabratetop</code> 找出哪个缓存的分配频率或占用字节数最反常。</li><li><strong>第二步</strong>：用动态 kprobes 抓取内核栈，看看具体是哪条代码路径在疯狂分配这个缓存。</li></ol><p>我们来实战一下。</p><p>首先，跑一下 <code>slabratetop</code>（或者 <code>slabratetop-bpfcc</code>）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slabratetop-bpfcc</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[...]</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">CACHE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">                            ALLOCS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      BYTES</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">names_cache</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">                          18</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      78336</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vm_area_struct</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">                      176</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      46464</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>在这段输出里（Figure 6.11 上半部分），我看到一个叫 <code>vm_area_struct</code> 的缓存分配频率特别高（每秒 176 次）。这很可疑。</p><p><em>(Figure 6.11 – Output from slabinfo and slabratetop)</em></p><p>现在的问题是：<strong>谁在分配 <code>vm_area_struct</code>？</strong></p><p>我们知道，内核分配特定缓存对象，最终都要调用 <code>kmem_cache_alloc()</code>。如果我们能实时看到这个函数的内核栈，不就知道是谁调用的了吗？</p><p>这就轮到 kprobe 出场了（回顾一下第 4 章的内容）。我们可以用 <code>kprobe-perf</code> 脚本来抓取 <code>kmem_cache_alloc</code> 的调用栈。</p><p>但有个细节：<code>kmem_cache_alloc</code> 的第一个参数是指向 <code>struct kmem_cache</code> 的指针。我们怎么知道这究竟是哪个缓存的指针呢？ 在 x86_64 上，第一个参数通过 <code>RDI</code> 寄存器传递。而 <code>struct kmem_cache</code> 结构体里，偏移量 96 字节的地方就是 <code>name</code> 成员（缓存的名字）。</p><p>所以我们的命令可以这么写：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kprobe-perf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;p:kmem_cache_alloc name=+0(+96(%di)):string&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这会打印所有 slab 分配的栈。为了只看我们关心的 <code>vm_area_struct</code>，用 <code>grep</code> 过滤一下：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kprobe-perf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;p:kmem_cache_alloc name=+0(+96(%di)):string&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;name=.*vm_area_struct&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你会得到类似下面的输出（Figure 6.11 下半部分）：</p><p><em>(Figure 6.11 – Kernel stack trace showing the call path to kmem_cache_alloc)</em></p><p>这栈非常清晰： <code>sys_brk() --&gt; do_brk() --&gt; do_brk_flags() --&gt; vm_area_alloc() --&gt; kmem_cache_alloc()</code></p><p><code>sys_brk</code> 是用户空间 <code>brk()</code> 系统调用的入口，通常用于扩展堆内存。 内核为了管理进程的内存区域，需要维护 VMA（Virtual Memory Area）结构。每当需要新建或扩展一个内存映射时，内核就得从 <code>vm_area_struct</code> 这个专有缓存里分配一个对象。 这就是这一连串分配的源头。</p><p>如果你去翻源码，能在 <code>mm/mmap.c</code> 里找到这一行： <a href="https://elixir.bootlin.com/linux/v5.10.60/source/mm/mmap.c#L3110" target="_blank" rel="noreferrer">https://elixir.bootlin.com/linux/v5.10.60/source/mm/mmap.c#L3110</a></p><p>看到这里，你应该对系统的内存行为有了一种「透视」感。</p><hr><p><strong>Security Tip</strong></p><p>最后，虽然稍微跑题一点，但这很重要：安全。 为了保证 slab 内存在分配时和释放时的内容都被彻底擦除（防止信息泄露），你可以在内核启动参数里加上： <code>init_on_alloc=1 init_on_free=1</code></p><p>这会有性能损耗，但对于高安全要求的场景，这是值得的。 参考一下 Kernel Self Protection Project 的建议： <a href="https://kernsec.org/wiki/index.php/Kernel_Self_Protection_Project/Recommended_Settings" target="_blank" rel="noreferrer">https://kernsec.org/wiki/index.php/Kernel_Self_Protection_Project/Recommended_Settings</a></p>`,109)])])}const g=i(n,[["render",t]]);export{c as __pageData,g as default};
